target datalayout = "e-p:64:64-p1:16:16-p2:32:32:32-p3:64:64:64"

define ptr @gep_ashr(ptr %p, i64 %off) {
  %index = ashr exact i64 %off, 2
  %ptr = getelementptr i32, ptr %p, i64 %index
  ret ptr %ptr
}

